<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Discover the Exit</title>
<style>
  :root { color-scheme: dark; }
  body {
    margin: 0;
    background: #101522;
    color: #eef3ff;
    font-family: Arial, sans-serif;
    display: flex;
    justify-content: center;
  }
  main { width: min(94vw, 700px); padding: 18px; text-align: center; }
  h1 { margin: 0 0 10px; font-size: 24px; }
  #info {
    display: flex;
    justify-content: center;
    gap: 26px;
    margin-bottom: 12px;
    font-size: 17px;
  }
  #maze {
    width: min(92vw, 630px);
    aspect-ratio: 1;
    margin: auto;
    background: #182033;
    border: 2px solid #506080;
    box-sizing: border-box;
  }
  canvas { display: block; width: 100%; height: 100%; }
  button {
    margin-top: 13px;
    padding: 8px 18px;
    border: 1px solid #8294bd;
    border-radius: 5px;
    background: #263451;
    color: white;
    cursor: pointer;
    font-size: 15px;
  }
  button:hover { background: #35486d; }
  .hint { color: #aebbd7; font-size: 13px; margin-top: 9px; }
</style>
</head>
<body>
<main>
  <h1>Maze Expedition</h1>
  <div id="info">
    <span>Completed: <b id="completed">0 / 24</b></span>
    <span>Timer: <b id="timer">0</b></span>
  </div>
  <div id="maze"><canvas id="canvas" width="630" height="630"></canvas></div>
  <button id="reset">Reset</button>
  <button id="run">Run</button>
  <div class="hint">Each colored explorer independently discovers the maze.</div>
</main>

<script>
(function () {
  "use strict";

  const ROWS = 21, COLS = 21, BOT_COUNT = 24;
  const canvas = document.getElementById("canvas");
  const ctx = canvas.getContext("2d");
  const completedEl = document.getElementById("completed");
  const timerEl = document.getElementById("timer");
  const resetBtn = document.getElementById("reset");
  const runBtn = document.getElementById("run");

  const DIRS = [
    { name: "n", dr: -1, dc: 0, opposite: "s" },
    { name: "e", dr: 0, dc: 1, opposite: "w" },
    { name: "s", dr: 1, dc: 0, opposite: "n" },
    { name: "w", dr: 0, dc: -1, opposite: "e" }
  ];

  let seedValue = 1;
  let maze = [];
  let bots = [];
  let spawn = { r: 0, c: 0 };
  let exitCell = { r: ROWS - 1, c: COLS - 1 };
  let elapsed = 0;
  let completed = 0;
  let raf = 0;
  let runner = null;

  function rng(seed) {
    let x = (seed >>> 0) || 1;
    return function () {
      x ^= x << 13;
      x ^= x >>> 17;
      x ^= x << 5;
      return ((x >>> 0) / 4294967296);
    };
  }

  function cellKey(r, c) { return r + "," + c; }
  function edgeKey(a, b) {
    const x = cellKey(a.r, a.c), y = cellKey(b.r, b.c);
    return x < y ? x + "|" + y : y + "|" + x;
  }

  function makeMaze(seed) {
    const random = rng(seed);
    maze = Array.from({length: ROWS}, () =>
      Array.from({length: COLS}, () => ({ n:true, e:true, s:true, w:true }))
    );

    const visited = Array.from({length: ROWS}, () => Array(COLS).fill(false));
    const stack = [{r:0, c:0}];
    visited[0][0] = true;

    while (stack.length) {
      const cur = stack[stack.length - 1];
      const choices = [];
      for (const d of DIRS) {
        const nr = cur.r + d.dr, nc = cur.c + d.dc;
        if (nr >= 0 && nr < ROWS && nc >= 0 && nc < COLS && !visited[nr][nc]) {
          choices.push({d, nr, nc});
        }
      }
      if (!choices.length) {
        stack.pop();
        continue;
      }
      const pick = choices[Math.floor(random() * choices.length)];
      maze[cur.r][cur.c][pick.d.name] = false;
      maze[pick.nr][pick.nc][pick.d.opposite] = false;
      visited[pick.nr][pick.nc] = true;
      stack.push({r:pick.nr, c:pick.nc});
    }
  }

  function makeBot(id, seed) {
    const random = rng((seed + 0x9e3779b9 * (id + 1)) >>> 0);
    const order = [0,1,2,3];

    // Give every explorer a different, deterministic local preference.
    for (let i = order.length - 1; i > 0; i--) {
      const j = Math.floor(random() * (i + 1));
      [order[i], order[j]] = [order[j], order[i]];
    }

    const b = {
      id,
      r: 0, c: 0,
      path: [{r:0, c:0}],
      deadEnds: [],
      finishTick: null,

      // Private exploration memory:
      stack: [{r:0, c:0}],
      traversed: new Set(),
      deadSet: new Set(),
      order,

      // Rendering state:
      fromR: 0, fromC: 0,
      toR: 0, toC: 0,
      motionStart: performance.now()
    };
    return b;
  }

  function currentOpenDirections(bot) {
    // This is the bot's local observation: it only examines walls at its
    // present cell. It does not inspect neighboring cells or the maze graph.
    const w = maze[bot.r][bot.c];
    return bot.order.filter(i => !w[DIRS[i].name]);
  }

  function stepBot(bot, tickNumber) {
    if (bot.finishTick !== null) return;

    if (bot.r === exitCell.r && bot.c === exitCell.c) {
      bot.finishTick = tickNumber;
      completed++;
      return;
    }

    const open = currentOpenDirections(bot);
    let chosen = null;

    for (const di of open) {
      const d = DIRS[di];
      const nr = bot.r + d.dr, nc = bot.c + d.dc;
      const k = edgeKey({r:bot.r,c:bot.c}, {r:nr,c:nc});
      if (!bot.traversed.has(k)) {
        chosen = {d, nr, nc, k};
        break;
      }
    }

    let nr, nc, k;
    if (chosen) {
      nr = chosen.nr;
      nc = chosen.nc;
      k = chosen.k;
      bot.traversed.add(k);
      bot.stack.push({r:nr, c:nc});
    } else if (bot.stack.length > 1) {
      // No unexplored local passage remains: mark this branch dead and
      // backtrack over the already-used tree edge.
      const here = {r:bot.r, c:bot.c};
      const hk = cellKey(here.r, here.c);
      if (!bot.deadSet.has(hk)) {
        bot.deadSet.add(hk);
        bot.deadEnds.push({r:here.r, c:here.c});
      }

      bot.stack.pop();
      const parent = bot.stack[bot.stack.length - 1];
      nr = parent.r;
      nc = parent.c;
      k = edgeKey(here, parent);
      bot.traversed.add(k);
    } else {
      // This can only happen if the exit is the starting cell or if the
      // entire reachable maze has been searched without finding it.
      return;
    }

    bot.fromR = bot.r;
    bot.fromC = bot.c;
    bot.r = nr;
    bot.c = nc;
    bot.toR = nr;
    bot.toC = nc;
    bot.motionStart = performance.now();
    bot.path.push({r:nr, c:nc});

    if (bot.r === exitCell.r && bot.c === exitCell.c) {
      bot.finishTick = tickNumber;
      completed++;
    }
  }

  function draw() {
    const W = canvas.width, H = canvas.height;
    const cw = W / COLS, ch = H / ROWS;
    ctx.clearRect(0, 0, W, H);
    ctx.fillStyle = "#182033";
    ctx.fillRect(0, 0, W, H);

    // Exit marker.
    ctx.fillStyle = "#45e08a";
    ctx.fillRect(exitCell.c*cw + cw*.22, exitCell.r*ch + ch*.22, cw*.56, ch*.56);
    ctx.fillStyle = "#10251b";
    ctx.font = "bold " + Math.floor(cw*.38) + "px Arial";
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText("EXIT", (exitCell.c+.5)*cw, (exitCell.r+.5)*ch);

    // Maze walls.
    ctx.strokeStyle = "#d7e2ff";
    ctx.lineWidth = Math.max(2, cw * .075);
    ctx.lineCap = "square";
    ctx.beginPath();
    for (let r=0; r<ROWS; r++) {
      for (let c=0; c<COLS; c++) {
        const x=c*cw, y=r*ch, w=maze[r][c];
        if (w.n) { ctx.moveTo(x,y); ctx.lineTo(x+cw,y); }
        if (w.e) { ctx.moveTo(x+cw,y); ctx.lineTo(x+cw,y+ch); }
        if (w.s) { ctx.moveTo(x,y+ch); ctx.lineTo(x+cw,y+ch); }
        if (w.w) { ctx.moveTo(x,y); ctx.lineTo(x,y+ch); }
      }
    }
    ctx.stroke();

    const now = performance.now();
    bots.forEach((b, i) => {
      let t = Math.min(1, (now - b.motionStart) / 120);
      if (b.finishTick !== null) t = 1;
      const rr = b.fromR + (b.toR - b.fromR) * t;
      const cc = b.fromC + (b.toC - b.fromC) * t;
      const x = (cc+.5)*cw, y = (rr+.5)*ch;
      ctx.beginPath();
      ctx.fillStyle = "hsl(" + ((i * 定 137) % 360) + ",82%,62%)".replace("定 ","");
      ctx.arc(x, y, Math.max(3.5, cw*.23), 0, Math.PI*2);
      ctx.fill();
      ctx.lineWidth = 1.5;
      ctx.strokeStyle = "rgba(255,255,255,.75)";
      ctx.stroke();
    });

    completedEl.textContent = completed + " / " + BOT_COUNT;
    timerEl.textContent = elapsed;
    if (bots.some(b => b.finishTick === null)) raf = requestAnimationFrame(draw);
    else raf = 0;
  }

  function reset(seed) {
    if (typeof seed === "number" && Number.isFinite(seed)) {
      seedValue = seed >>> 0;
    } else {
      seedValue = (Date.now() ^ Math.floor(Math.random()*0xffffffff)) >>> 0;
    }
    if (raf) cancelAnimationFrame(raf);
    if (runner) { clearInterval(runner); runner = null; runBtn.textContent = "Run"; }
    makeMaze(seedValue);
    bots = Array.from({length: BOT_COUNT}, (_, i) => makeBot(i, seedValue));
    elapsed = 0;
    completed = 0;
    draw();
  }

  function tick(n) {
    n = Math.max(0, Math.floor(Number(n) || 0));
    for (let i=0; i<n; i++) {
      if (completed === BOT_COUNT) break;
      elapsed++;
      for (const bot of bots) stepBot(bot, elapsed);
    }
    draw();
  }

  window.game = {
    tick,
    reset,
    get elapsed() { return elapsed; },
    size: {rows: ROWS, cols: COLS},
    spawn: spawn,
    exit: exitCell,
    walls(r, c) {
      const w = maze[r][c];
      return {n:!!w.n, e:!!w.e, s:!!w.s, w:!!w.w};
    },
    get bots() { return bots; }
  };

  reset(123456789);

  resetBtn.addEventListener("click", () => reset());
  runBtn.addEventListener("click", () => {
    if (runner) {
      clearInterval(runner);
      runner = null;
      runBtn.textContent = "Run";
    } else {
      runner = setInterval(() => {
        if (completed === BOT_COUNT) {
          clearInterval(runner);
          runner = null;
          runBtn.textContent = "Run";
        } else {
          tick(1);
        }
      }, 90);
      runBtn.textContent = "Pause";
    }
  });
})();
</script>
</body>
</html>
